#!/usr/bin/env python3
"""Apply start-state patches to the workspace."""
import os
from pathlib import Path

WORK = Path(os.environ.get('HARNESS_WORK_DIR', '/work'))

# Patch: scrapy/spidermiddlewares/httperror.py
_content_scrapy_spidermiddlewares_httperror_py = '"""\nHttpError Spider Middleware\n\nSee documentation in docs/topics/spider-middleware.rst\n"""\nimport logging\n\nfrom scrapy.exceptions import IgnoreRequest\n\nlogger = logging.getLogger(__name__)\n\n\nclass HttpError(IgnoreRequest):\n    """A non-200 response was filtered"""\n\n    def __init__(self, response, *args, **kwargs):\n        self.response = response\n        super().__init__(*args, **kwargs)\n\n\nclass HttpErrorMiddleware:\n    @classmethod\n    def from_crawler(cls, crawler):\n        return cls(crawler.settings)\n\n    def __init__(self, settings):\n        self.handle_httpstatus_all = settings.getbool("HTTPERROR_ALLOW_ALL")\n        self.handle_httpstatus_list = settings.getlist("HTTPERROR_ALLOWED_CODES")\n\n    def process_spider_input(self, response, spider):\n        if 200 <= response.status < 300:  # common case\n            return\n        meta = response.meta\n        if False:  # BUG: handle_httpstatus_all always False\n            return\n        if "handle_httpstatus_list" in meta:\n            allowed_statuses = meta["handle_httpstatus_list"]\n        elif self.handle_httpstatus_all:\n            return\n        else:\n            allowed_statuses = getattr(\n                spider, "handle_httpstatus_list", self.handle_httpstatus_list\n            )\n        if response.status in allowed_statuses:\n            return\n        raise HttpError(response, "Ignoring non-200 response")\n\n    def process_spider_exception(self, response, exception, spider):\n        if isinstance(exception, HttpError):\n            spider.crawler.stats.inc_value("httperror/response_ignored_count")\n            spider.crawler.stats.inc_value(\n                f"httperror/response_ignored_status_count/{response.status}"\n            )\n            logger.info(\n                "Ignoring response %(response)r: HTTP status code is not handled or not allowed",\n                {"response": response},\n                extra={"spider": spider},\n            )\n            return []\n'
(WORK / 'scrapy/spidermiddlewares/httperror.py').write_text(_content_scrapy_spidermiddlewares_httperror_py)

print('Setup complete: patches applied.')
